import java.io.*;

public class SecureCommandExecutionExample {
    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a file name to display its contents: ");
            String fileName = br.readLine();

            // Secure code that uses ProcessBuilder to execute the command safely
            ProcessBuilder processBuilder = new ProcessBuilder("cat", fileName);
            Process process = processBuilder.start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Command Injection
